import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';
import Spinner from '../../components/Spinner';

const roles = [
  { value:'donor', label:'Donor', icon:'🍱' },
  { value:'ngo', label:'NGO', icon:'🏢' },
  { value:'volunteer', label:'Volunteer', icon:'🙌' }
];

const Signup = ()=>{

const [form,setForm]=useState({
name:'',
email:'',
password:'',
role:''
});

const [certificateFile,setCertificateFile]=
useState(null);

const [loading,setLoading]=
useState(false);

const {signup}=useAuth();

const navigate=useNavigate();



const handleChange=(e)=>
setForm({
...form,
[e.target.name]:
e.target.value
});


const selectRole=(role)=>
setForm({
...form,
role
});


const handleCertificateUpload=(e)=>{

const file=e.target.files[0];

setCertificateFile(file);

};




const handleSubmit=async(e)=>{

e.preventDefault();


if(!form.role){

toast.error(
'Please select a role'
);

return;

}



if(
form.role==='ngo'
&&
!certificateFile
){

toast.error(
'Please upload NGO Registration Certificate'
);

return;

}


setLoading(true);


try{

let uploadedCertificate='';



// NEW FILE UPLOAD

if(
form.role==='ngo'
&&
certificateFile
){

const formData=
new FormData();

formData.append(
'certificate',
certificateFile
);



const uploadRes=
await fetch(

'http://localhost:5000/api/upload/certificate',

{
method:'POST',
body:formData
}

);


const uploadData=
await uploadRes.json();

uploadedCertificate=
uploadData.filePath;

console.log(
'Uploaded:',
uploadedCertificate
);

}



// EXISTING SIGNUP

const user=
await signup(

form.name,

form.email,

form.password,

form.role

// next step later:
 // we can pass uploadedCertificate
 // into backend signup too

);



toast.success(
`Welcome to ShareBite, ${user.name}! 🎉`
);



if(
user.role==='admin'
){

navigate(
'/admin-dashboard'
);

}

else if(
user.role==='donor'
){

navigate(
'/donor-dashboard'
);

}

else if(
user.role==='ngo'
){

navigate(
'/ngo-dashboard'
);

}

else{

navigate(
'/volunteer-dashboard'
);

}


}

catch(err){

toast.error(

err.response?.data?.message

||

'Signup failed'

);

}

finally{

setLoading(false);

}

};



return(

<div className="min-h-screen flex">

<div className="w-full lg:w-1/2 flex items-center justify-center px-6 py-12">

<div className="w-full max-w-md">

<h1>
Create account
</h1>



<div className="mb-6">

<div className="grid grid-cols-3 gap-3">

{roles.map((r)=>(

<button

key={r.value}

type="button"

onClick={()=>
selectRole(
r.value
)
}

>

{r.icon}

<br/>

{r.label}

</button>

))}

</div>

</div>



<form
onSubmit={handleSubmit}
className="space-y-4"
>

<input
type="text"
name="name"
value={form.name}
onChange={handleChange}
placeholder="Full name"
required
/>


<input
type="email"
name="email"
value={form.email}
onChange={handleChange}
placeholder="Email"
required
/>


<input
type="password"
name="password"
value={form.password}
onChange={handleChange}
placeholder="Password"
required
/>


{form.role==='ngo'&&(

<div>

<label>
Upload NGO Registration Certificate
</label>

<input
type="file"
accept=".pdf,.jpg,.png"
onChange={handleCertificateUpload}
/>

{certificateFile&&(

<p>
Selected:
{certificateFile.name}
</p>

)}

</div>

)}



<button
type="submit"
disabled={loading}
>

{loading
?'Creating...'
:'Create Account'
}

</button>

</form>


<Link to="/login">
Already have an account?
</Link>

</div>

</div>

</div>

);

};

export default Signup;
